package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withAllowMissingColumnNames();
        assertNotNull(newFormat);
        assertTrue(newFormat.getAllowMissingColumnNames());
        // Original instance should remain unchanged
        assertFalse(format.getAllowMissingColumnNames());
        // Chaining returns a new instance
        CSVFormat chainedFormat = format.withAllowMissingColumnNames(true).withAllowMissingColumnNames(false);
        assertFalse(chainedFormat.getAllowMissingColumnNames());
    }
}
